typedef struct cct_rt_map_entry {
    unsigned char *key;
    unsigned char *value;
    struct cct_rt_map_entry *next;
} cct_rt_map_entry_t;

typedef struct {
    cct_rt_map_entry_t **buckets;
    size_t capacity;
    size_t len;
    size_t key_size;
    size_t value_size;
    cct_rt_map_entry_t **insert_order;
    size_t insert_capacity;
} cct_rt_map_t;

typedef struct {
    cct_rt_map_t *map;
} cct_rt_set_t;

static size_t cct_rt_map_min_storage_size(size_t n) {
    return (n == 0) ? 1 : n;
}

static size_t cct_rt_map_hash_bytes(const void *data, size_t size) {
    const unsigned char *p = (const unsigned char*)data;
    size_t h = (size_t)1469598103934665603ULL;
    for (size_t i = 0; i < size; i++) {
        h ^= (size_t)p[i];
        h *= (size_t)1099511628211ULL;
    }
    return h;
}

static void cct_rt_map_require(void *map_ptr, const char *ctx) {
    if (!map_ptr) cct_rt_fail((ctx && *ctx) ? ctx : "map received null instance");
}

static cct_rt_map_entry_t *cct_rt_map_entry_new(const void *key_ptr, size_t key_size, const void *value_ptr, size_t value_size) {
    cct_rt_map_entry_t *e = (cct_rt_map_entry_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_map_entry_t));
    e->key = (unsigned char*)cct_rt_alloc_or_fail(key_size);
    e->value = (unsigned char*)cct_rt_alloc_or_fail(value_size);
    memcpy(e->key, key_ptr, key_size);
    memcpy(e->value, value_ptr, value_size);
    e->next = NULL;
    return e;
}

static void cct_rt_map_entry_free(cct_rt_map_entry_t *e) {
    if (!e) return;
    cct_rt_free_ptr(e->key);
    cct_rt_free_ptr(e->value);
    cct_rt_free_ptr(e);
}

static void cct_rt_map_insert_order_reserve(cct_rt_map_t *map, size_t needed) {
    if (needed <= map->insert_capacity) return;
    size_t cap = map->insert_capacity ? map->insert_capacity * 2 : 16;
    while (cap < needed) cap *= 2;
    cct_rt_map_entry_t **next = (cct_rt_map_entry_t**)realloc(map->insert_order, cap * sizeof(cct_rt_map_entry_t*));
    if (!next) cct_rt_fail("map insert-order allocation failed");
    map->insert_order = next;
    map->insert_capacity = cap;
}

static void cct_rt_map_insert_order_append(cct_rt_map_t *map, cct_rt_map_entry_t *entry) {
    cct_rt_map_insert_order_reserve(map, map->len + 1);
    map->insert_order[map->len] = entry;
}

static void cct_rt_map_insert_order_remove(cct_rt_map_t *map, cct_rt_map_entry_t *entry) {
    if (!map || !entry || map->len == 0) return;
    for (size_t i = 0; i < map->len; i++) {
        if (map->insert_order[i] != entry) continue;
        if (i + 1 < map->len) {
            memmove(&map->insert_order[i], &map->insert_order[i + 1], (map->len - i - 1) * sizeof(cct_rt_map_entry_t*));
        }
        map->insert_order[map->len - 1] = NULL;
        return;
    }
}

static size_t cct_rt_map_bucket_index(cct_rt_map_t *map, const void *key_ptr) {
    size_t h = cct_rt_map_hash_bytes(key_ptr, map->key_size);
    return (map->capacity == 0) ? 0 : (h % map->capacity);
}

static void cct_rt_map_rehash(cct_rt_map_t *map, size_t new_capacity) {
    cct_rt_map_entry_t **new_buckets = (cct_rt_map_entry_t**)calloc(new_capacity, sizeof(cct_rt_map_entry_t*));
    if (!new_buckets) cct_rt_fail("map rehash allocation failed");
    for (size_t i = 0; i < map->capacity; i++) {
        cct_rt_map_entry_t *e = map->buckets[i];
        while (e) {
            cct_rt_map_entry_t *next = e->next;
            size_t idx = cct_rt_map_hash_bytes(e->key, map->key_size) % new_capacity;
            e->next = new_buckets[idx];
            new_buckets[idx] = e;
            e = next;
        }
    }
    cct_rt_free_ptr(map->buckets);
    map->buckets = new_buckets;
    map->capacity = new_capacity;
}

static void *cct_rt_map_init(long long key_size, long long value_size) {
    if (key_size <= 0) cct_rt_fail("map_init key size must be > 0");
    if (value_size < 0) cct_rt_fail("map_init value size must be >= 0");
    cct_rt_map_t *map = (cct_rt_map_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_map_t));
    map->capacity = 16;
    map->len = 0;
    map->key_size = cct_rt_map_min_storage_size((size_t)key_size);
    map->value_size = cct_rt_map_min_storage_size((size_t)value_size);
    map->buckets = (cct_rt_map_entry_t**)calloc(map->capacity, sizeof(cct_rt_map_entry_t*));
    if (!map->buckets) cct_rt_fail("map_init buckets allocation failed");
    map->insert_order = NULL;
    map->insert_capacity = 0;
    return map;
}

static void cct_rt_map_insert(void *map_ptr, const void *key_ptr, const void *value_ptr) {
    cct_rt_map_require(map_ptr, "map_insert received null map");
    if (!key_ptr) cct_rt_fail("map_insert received null key pointer");
    if (!value_ptr) cct_rt_fail("map_insert received null value pointer");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    if (map->capacity == 0) cct_rt_fail("map_insert map capacity invalid");
    if ((map->len + 1) * 4 >= map->capacity * 3) {
        cct_rt_map_rehash(map, map->capacity * 2);
    }
    size_t idx = cct_rt_map_bucket_index(map, key_ptr);
    cct_rt_map_entry_t *e = map->buckets[idx];
    while (e) {
        if (memcmp(e->key, key_ptr, map->key_size) == 0) {
            memcpy(e->value, value_ptr, map->value_size);
            return;
        }
        e = e->next;
    }
    cct_rt_map_entry_t *ne = cct_rt_map_entry_new(key_ptr, map->key_size, value_ptr, map->value_size);
    ne->next = map->buckets[idx];
    map->buckets[idx] = ne;
    cct_rt_map_insert_order_append(map, ne);
    map->len += 1;
}

static void *cct_rt_map_get_ptr(void *map_ptr, const void *key_ptr) {
    cct_rt_map_require(map_ptr, "map_get_ptr received null map");
    if (!key_ptr) cct_rt_fail("map_get_ptr received null key pointer");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    size_t idx = cct_rt_map_bucket_index(map, key_ptr);
    cct_rt_map_entry_t *e = map->buckets[idx];
    while (e) {
        if (memcmp(e->key, key_ptr, map->key_size) == 0) return (void*)e->value;
        e = e->next;
    }
    return NULL;
}

static long long cct_rt_map_contains(void *map_ptr, const void *key_ptr) {
    return cct_rt_map_get_ptr(map_ptr, key_ptr) ? 1LL : 0LL;
}

static long long cct_rt_map_remove(void *map_ptr, const void *key_ptr) {
    cct_rt_map_require(map_ptr, "map_remove received null map");
    if (!key_ptr) cct_rt_fail("map_remove received null key pointer");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    size_t idx = cct_rt_map_bucket_index(map, key_ptr);
    cct_rt_map_entry_t *e = map->buckets[idx];
    cct_rt_map_entry_t *prev = NULL;
    while (e) {
        if (memcmp(e->key, key_ptr, map->key_size) == 0) {
            if (prev) prev->next = e->next;
            else map->buckets[idx] = e->next;
            cct_rt_map_insert_order_remove(map, e);
            cct_rt_map_entry_free(e);
            map->len -= 1;
            return 1LL;
        }
        prev = e;
        e = e->next;
    }
    return 0LL;
}

static long long cct_rt_map_len(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_len received null map");
    return (long long)((cct_rt_map_t*)map_ptr)->len;
}

static long long cct_rt_map_is_empty(void *map_ptr) {
    return cct_rt_map_len(map_ptr) == 0 ? 1LL : 0LL;
}

static long long cct_rt_map_capacity(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_capacity received null map");
    return (long long)((cct_rt_map_t*)map_ptr)->capacity;
}

static void cct_rt_map_clear(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_clear received null map");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    for (size_t i = 0; i < map->capacity; i++) {
        cct_rt_map_entry_t *e = map->buckets[i];
        while (e) {
            cct_rt_map_entry_t *next = e->next;
            cct_rt_map_entry_free(e);
            e = next;
        }
        map->buckets[i] = NULL;
    }
    if (map->insert_order && map->len > 0) {
        memset(map->insert_order, 0, map->len * sizeof(cct_rt_map_entry_t*));
    }
    map->len = 0;
}

static void cct_rt_map_reserve(void *map_ptr, long long additional) {
    cct_rt_map_require(map_ptr, "map_reserve received null map");
    if (additional < 0) cct_rt_fail("map_reserve additional must be >= 0");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    size_t need = map->len + (size_t)additional;
    size_t target = map->capacity;
    while (need * 4 >= target * 3) {
        target *= 2;
    }
    if (target > map->capacity) cct_rt_map_rehash(map, target);
}

static void *cct_rt_map_copy(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_copy received null map");
    cct_rt_map_t *src = (cct_rt_map_t*)map_ptr;
    cct_rt_map_t *dst = (cct_rt_map_t*)cct_rt_map_init((long long)src->key_size, (long long)src->value_size);
    cct_rt_map_reserve(dst, (long long)src->len);
    for (size_t i = 0; i < src->len; i++) {
        cct_rt_map_entry_t *e = src->insert_order[i];
        if (!e) continue;
        cct_rt_map_insert(dst, (const void*)e->key, (const void*)e->value);
    }
    return dst;
}

static void *cct_rt_map_keys(void *map_ptr, long long key_size) {
    cct_rt_map_require(map_ptr, "map_keys received null map");
    if (key_size <= 0) cct_rt_fail("map_keys key_size must be > 0");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    if (cct_rt_map_min_storage_size((size_t)key_size) != map->key_size) cct_rt_fail("map_keys key_size mismatch");
    void *out_f = cct_rt_fluxus_create(key_size);
    cct_rt_fluxus_reserve(out_f, (long long)map->len);
    for (size_t i = 0; i < map->len; i++) {
        cct_rt_map_entry_t *e = map->insert_order[i];
        if (!e) continue;
        cct_rt_fluxus_push(out_f, (const void*)e->key);
    }
    return out_f;
}

static void *cct_rt_map_values(void *map_ptr, long long value_size) {
    cct_rt_map_require(map_ptr, "map_values received null map");
    if (value_size <= 0) cct_rt_fail("map_values value_size must be > 0");
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    if (cct_rt_map_min_storage_size((size_t)value_size) != map->value_size) cct_rt_fail("map_values value_size mismatch");
    void *out_f = cct_rt_fluxus_create(value_size);
    cct_rt_fluxus_reserve(out_f, (long long)map->len);
    for (size_t i = 0; i < map->len; i++) {
        cct_rt_map_entry_t *e = map->insert_order[i];
        if (!e) continue;
        cct_rt_fluxus_push(out_f, (const void*)e->value);
    }
    return out_f;
}

static void cct_rt_map_merge(void *dest_ptr, void *src_ptr) {
    cct_rt_map_require(dest_ptr, "map_merge received null destination map");
    cct_rt_map_require(src_ptr, "map_merge received null source map");
    cct_rt_map_t *dest = (cct_rt_map_t*)dest_ptr;
    cct_rt_map_t *src = (cct_rt_map_t*)src_ptr;
    if (dest->key_size != src->key_size || dest->value_size != src->value_size) cct_rt_fail("map_merge requires compatible key/value sizes");
    cct_rt_map_reserve(dest, (long long)src->len);
    for (size_t i = 0; i < src->len; i++) {
        cct_rt_map_entry_t *e = src->insert_order[i];
        if (!e) continue;
        cct_rt_map_insert(dest, (const void*)e->key, (const void*)e->value);
    }
}

typedef struct {
    cct_rt_map_t *map;
    size_t index;
} cct_rt_map_iter_t;

static void *cct_rt_map_iter_begin(void *map_ptr) {
    cct_rt_map_require(map_ptr, "map_iter_begin received null map");
    cct_rt_map_iter_t *it = (cct_rt_map_iter_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_map_iter_t));
    it->map = (cct_rt_map_t*)map_ptr;
    it->index = 0;
    return it;
}

static long long cct_rt_map_iter_next(void *iter_ptr, void **key_ptr_out, void **value_ptr_out) {
    if (!iter_ptr) cct_rt_fail("map_iter_next received null iterator");
    if (!key_ptr_out || !value_ptr_out) cct_rt_fail("map_iter_next requires key/value out pointers");
    cct_rt_map_iter_t *it = (cct_rt_map_iter_t*)iter_ptr;
    if (!it->map) cct_rt_fail("map_iter_next iterator has null map");
    while (it->index < it->map->len) {
        cct_rt_map_entry_t *e = it->map->insert_order[it->index++];
        if (!e) continue;
        *key_ptr_out = (void*)e->key;
        *value_ptr_out = (void*)e->value;
        return 1LL;
    }
    return 0LL;
}

static void cct_rt_map_iter_end(void *iter_ptr) {
    if (!iter_ptr) return;
    cct_rt_free_ptr(iter_ptr);
}

static void cct_rt_map_free(void *map_ptr) {
    if (!map_ptr) return;
    cct_rt_map_t *map = (cct_rt_map_t*)map_ptr;
    cct_rt_map_clear(map);
    cct_rt_free_ptr(map->buckets);
    cct_rt_free_ptr(map->insert_order);
    cct_rt_free_ptr(map);
}

static void *cct_rt_set_init(long long item_size) {
    cct_rt_set_t *set = (cct_rt_set_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_set_t));
    set->map = (cct_rt_map_t*)cct_rt_map_init(item_size, 1);
    return set;
}

static long long cct_rt_set_insert(void *set_ptr, const void *item_ptr) {
    if (!set_ptr) cct_rt_fail("set_insert received null set");
    if (!item_ptr) cct_rt_fail("set_insert received null item pointer");
    cct_rt_set_t *set = (cct_rt_set_t*)set_ptr;
    size_t before = set->map->len;
    unsigned char marker = 1;
    cct_rt_map_insert(set->map, item_ptr, &marker);
    return (set->map->len > before) ? 1LL : 0LL;
}

static long long cct_rt_set_remove(void *set_ptr, const void *item_ptr) {
    if (!set_ptr) cct_rt_fail("set_remove received null set");
    if (!item_ptr) cct_rt_fail("set_remove received null item pointer");
    return cct_rt_map_remove(((cct_rt_set_t*)set_ptr)->map, item_ptr);
}

static long long cct_rt_set_contains(void *set_ptr, const void *item_ptr) {
    if (!set_ptr) cct_rt_fail("set_contains received null set");
    if (!item_ptr) cct_rt_fail("set_contains received null item pointer");
    return cct_rt_map_contains(((cct_rt_set_t*)set_ptr)->map, item_ptr);
}

static long long cct_rt_set_len(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_len received null set");
    return cct_rt_map_len(((cct_rt_set_t*)set_ptr)->map);
}

static long long cct_rt_set_is_empty(void *set_ptr) {
    return cct_rt_set_len(set_ptr) == 0 ? 1LL : 0LL;
}

static void cct_rt_set_clear(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_clear received null set");
    cct_rt_map_clear(((cct_rt_set_t*)set_ptr)->map);
}

static void cct_rt_set_reserve(void *set_ptr, long long additional) {
    if (!set_ptr) cct_rt_fail("set_reserve received null set");
    cct_rt_map_reserve(((cct_rt_set_t*)set_ptr)->map, additional);
}

static long long cct_rt_set_capacity(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_capacity received null set");
    return cct_rt_map_capacity(((cct_rt_set_t*)set_ptr)->map);
}

typedef struct {
    cct_rt_set_t *set;
    size_t index;
} cct_rt_set_iter_t;

static void *cct_rt_set_iter_begin(void *set_ptr) {
    if (!set_ptr) cct_rt_fail("set_iter_begin received null set");
    cct_rt_set_iter_t *it = (cct_rt_set_iter_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_set_iter_t));
    it->set = (cct_rt_set_t*)set_ptr;
    it->index = 0;
    return it;
}

static long long cct_rt_set_iter_next(void *iter_ptr, void **elem_ptr_out) {
    if (!iter_ptr) cct_rt_fail("set_iter_next received null iterator");
    if (!elem_ptr_out) cct_rt_fail("set_iter_next requires elem out pointer");
    cct_rt_set_iter_t *it = (cct_rt_set_iter_t*)iter_ptr;
    if (!it->set || !it->set->map) cct_rt_fail("set_iter_next iterator has null set/map");
    while (it->index < it->set->map->len) {
        cct_rt_map_entry_t *e = it->set->map->insert_order[it->index++];
        if (!e) continue;
        *elem_ptr_out = (void*)e->key;
        return 1LL;
    }
    return 0LL;
}

static void cct_rt_set_iter_end(void *iter_ptr) {
    if (!iter_ptr) return;
    cct_rt_free_ptr(iter_ptr);
}

static long long cct_rt_set_validate_item_size(cct_rt_set_t *set, long long item_size, const char *ctx) {
    if (!set) cct_rt_fail((ctx && *ctx) ? ctx : "set validation received null set");
    if (item_size <= 0) cct_rt_fail("set operation requires item_size > 0");
    if (cct_rt_map_min_storage_size((size_t)item_size) != set->map->key_size) {
        cct_rt_fail("set operation item_size mismatch");
    }
    return item_size;
}

static void *cct_rt_set_copy(void *set_ptr, long long item_size) {
    if (!set_ptr) cct_rt_fail("set_copy received null set");
    cct_rt_set_t *src = (cct_rt_set_t*)set_ptr;
    cct_rt_set_validate_item_size(src, item_size, "set_copy invalid input");
    cct_rt_set_t *dst = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_reserve(dst, (long long)src->map->len);
    for (size_t i = 0; i < src->map->len; i++) {
        cct_rt_map_entry_t *e = src->map->insert_order[i];
        if (!e) continue;
        cct_rt_set_insert(dst, (const void*)e->key);
    }
    return dst;
}

static void *cct_rt_set_to_fluxus(void *set_ptr, long long item_size) {
    if (!set_ptr) cct_rt_fail("set_to_fluxus received null set");
    cct_rt_set_t *set = (cct_rt_set_t*)set_ptr;
    cct_rt_set_validate_item_size(set, item_size, "set_to_fluxus invalid input");
    void *out_f = cct_rt_fluxus_create(item_size);
    cct_rt_fluxus_reserve(out_f, (long long)set->map->len);
    for (size_t i = 0; i < set->map->len; i++) {
        cct_rt_map_entry_t *e = set->map->insert_order[i];
        if (!e) continue;
        cct_rt_fluxus_push(out_f, (const void*)e->key);
    }
    return out_f;
}

static long long cct_rt_set_is_subset(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_is_subset received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_is_subset invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_is_subset invalid right set");
    if (a->map->len > b->map->len) return 0LL;
    for (size_t i = 0; i < a->map->len; i++) {
        cct_rt_map_entry_t *e = a->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(b, (const void*)e->key)) return 0LL;
    }
    return 1LL;
}

static long long cct_rt_set_equals(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_equals received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_equals invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_equals invalid right set");
    if (a->map->len != b->map->len) return 0LL;
    return cct_rt_set_is_subset(a, b, item_size);
}

static void *cct_rt_set_union(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_union received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_union invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_union invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_copy(a, item_size);
    cct_rt_set_reserve(out_s, (long long)b->map->len);
    for (size_t i = 0; i < b->map->len; i++) {
        cct_rt_map_entry_t *e = b->map->insert_order[i];
        if (!e) continue;
        cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void *cct_rt_set_intersection(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_intersection received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_intersection invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_intersection invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_t *probe = (a->map->len <= b->map->len) ? a : b;
    cct_rt_set_t *other = (probe == a) ? b : a;
    cct_rt_set_reserve(out_s, (long long)probe->map->len);
    for (size_t i = 0; i < probe->map->len; i++) {
        cct_rt_map_entry_t *e = probe->map->insert_order[i];
        if (!e) continue;
        if (cct_rt_set_contains(other, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void *cct_rt_set_difference(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_difference received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_difference invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_difference invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_reserve(out_s, (long long)a->map->len);
    for (size_t i = 0; i < a->map->len; i++) {
        cct_rt_map_entry_t *e = a->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(b, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void *cct_rt_set_symmetric_difference(void *a_ptr, void *b_ptr, long long item_size) {
    if (!a_ptr || !b_ptr) cct_rt_fail("set_symmetric_difference received null set");
    cct_rt_set_t *a = (cct_rt_set_t*)a_ptr;
    cct_rt_set_t *b = (cct_rt_set_t*)b_ptr;
    cct_rt_set_validate_item_size(a, item_size, "set_symmetric_difference invalid left set");
    cct_rt_set_validate_item_size(b, item_size, "set_symmetric_difference invalid right set");
    cct_rt_set_t *out_s = (cct_rt_set_t*)cct_rt_set_init(item_size);
    cct_rt_set_reserve(out_s, (long long)(a->map->len + b->map->len));
    for (size_t i = 0; i < a->map->len; i++) {
        cct_rt_map_entry_t *e = a->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(b, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    for (size_t i = 0; i < b->map->len; i++) {
        cct_rt_map_entry_t *e = b->map->insert_order[i];
        if (!e) continue;
        if (!cct_rt_set_contains(a, (const void*)e->key)) cct_rt_set_insert(out_s, (const void*)e->key);
    }
    return out_s;
}

static void cct_rt_set_free(void *set_ptr) {
    if (!set_ptr) return;
    cct_rt_set_t *set = (cct_rt_set_t*)set_ptr;
    cct_rt_map_free(set->map);
    cct_rt_free_ptr(set);
}

typedef struct {
    char *buf;
    size_t len;
    size_t cap;
} cct_rt_molde_ctx_t;

static cct_rt_molde_ctx_t *cct_rt_molde_begin(void) {
    cct_rt_molde_ctx_t *m = (cct_rt_molde_ctx_t*)malloc(sizeof(cct_rt_molde_ctx_t));
    if (!m) cct_rt_fail("MOLDE allocation failed");
    m->cap = 128;
    m->len = 0;
    m->buf = (char*)malloc(m->cap);
    if (!m->buf) cct_rt_fail("MOLDE buffer allocation failed");
    m->buf[0] = '\0';
    return m;
}

static void cct_rt_molde_append(cct_rt_molde_ctx_t *m, const char *s, size_t slen) {
    if (!m || !s || slen == 0) return;
    while (m->len + slen + 1 > m->cap) {
        size_t next = m->cap * 2;
        if (next <= m->cap) cct_rt_fail("MOLDE buffer overflow");
        char *grown = (char*)realloc(m->buf, next);
        if (!grown) cct_rt_fail("MOLDE realloc failed");
        m->buf = grown;
        m->cap = next;
    }
    memcpy(m->buf + m->len, s, slen);
    m->len += slen;
    m->buf[m->len] = '\0';
}

static void cct_rt_molde_str(cct_rt_molde_ctx_t *m, const char *s) {
    const char *src = s ? s : "";
    cct_rt_molde_append(m, src, strlen(src));
}

static void cct_rt_molde_rex(cct_rt_molde_ctx_t *m, long long v) {
    char tmp[64];
    int n = snprintf(tmp, sizeof(tmp), "%lld", v);
    if (n < 0) cct_rt_fail("MOLDE rex formatting failed");
    cct_rt_molde_append(m, tmp, (size_t)n);
}

static void cct_rt_molde_dux(cct_rt_molde_ctx_t *m, unsigned long long v) {
    char tmp[64];
    int n = snprintf(tmp, sizeof(tmp), "%llu", v);
    if (n < 0) cct_rt_fail("MOLDE dux formatting failed");
    cct_rt_molde_append(m, tmp, (size_t)n);
}

static void cct_rt_molde_umbra(cct_rt_molde_ctx_t *m, double v) {
    char tmp[128];
    int n = snprintf(tmp, sizeof(tmp), "%g", v);
    if (n < 0) cct_rt_fail("MOLDE umbra formatting failed");
    cct_rt_molde_append(m, tmp, (size_t)n);
}

static void cct_rt_molde_verum(cct_rt_molde_ctx_t *m, long long v) {
    const char *txt = v ? "verum" : "falsum";
    cct_rt_molde_append(m, txt, strlen(txt));
}

static void cct_rt_molde_fmt_build(char *fmt, size_t fmt_cap, const char *spec, const char *length_mod) {
    if (!fmt || fmt_cap == 0) cct_rt_fail("MOLDE format buffer invalid");
    if (!spec || !spec[0]) cct_rt_fail("MOLDE format spec vazio");
    size_t spec_len = strlen(spec);
    char conv = spec[spec_len - 1];
    size_t prefix_len = spec_len - 1;
    int n;
    if (length_mod && length_mod[0]) n = snprintf(fmt, fmt_cap, "%%%.*s%s%c", (int)prefix_len, spec, length_mod, conv);
    else n = snprintf(fmt, fmt_cap, "%%%s", spec);
    if (n < 0 || (size_t)n >= fmt_cap) cct_rt_fail("MOLDE format spec overflow");
}

static void cct_rt_molde_rex_fmt(cct_rt_molde_ctx_t *m, long long v, const char *spec) {
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, "ll");
    int need = snprintf(NULL, 0, fmt, v);
    if (need < 0) cct_rt_fail("MOLDE rex fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE rex fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, v);
    if (wrote != need) cct_rt_fail("MOLDE rex fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static void cct_rt_molde_dux_fmt(cct_rt_molde_ctx_t *m, unsigned long long v, const char *spec) {
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, "ll");
    int need = snprintf(NULL, 0, fmt, v);
    if (need < 0) cct_rt_fail("MOLDE dux fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE dux fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, v);
    if (wrote != need) cct_rt_fail("MOLDE dux fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static void cct_rt_molde_umbra_fmt(cct_rt_molde_ctx_t *m, double v, const char *spec) {
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, NULL);
    int need = snprintf(NULL, 0, fmt, v);
    if (need < 0) cct_rt_fail("MOLDE umbra fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE umbra fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, v);
    if (wrote != need) cct_rt_fail("MOLDE umbra fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static int cct_rt_molde_parse_align_spec(const char *spec, char *dir, long long *width) {
    if (!spec || !dir || !width) return 0;
    if (spec[0] != '<' && spec[0] != '>') return 0;
    if (!spec[1]) return 0;
    long long acc = 0;
    for (size_t i = 1; spec[i]; i++) {
        if (spec[i] < '0' || spec[i] > '9') return 0;
        acc = (acc * 10LL) + (long long)(spec[i] - '0');
        if (acc < 0) cct_rt_fail("MOLDE alignment width overflow");
    }
    *dir = spec[0];
    *width = acc;
    return 1;
}

static void cct_rt_molde_append_spaces(cct_rt_molde_ctx_t *m, size_t count) {
    while (count > 0) {
        cct_rt_molde_append(m, " ", 1);
        count--;
    }
}

static void cct_rt_molde_str_fmt(cct_rt_molde_ctx_t *m, const char *s, const char *spec) {
    const char *src = s ? s : "";
    char dir = '\0';
    long long width = 0;
    if (cct_rt_molde_parse_align_spec(spec, &dir, &width)) {
        size_t slen = strlen(src);
        size_t pad = (width > (long long)slen) ? (size_t)(width - (long long)slen) : 0;
        if (dir == '>') cct_rt_molde_append_spaces(m, pad);
        cct_rt_molde_append(m, src, slen);
        if (dir == '<') cct_rt_molde_append_spaces(m, pad);
        return;
    }
    char fmt[64];
    cct_rt_molde_fmt_build(fmt, sizeof(fmt), spec, NULL);
    int need = snprintf(NULL, 0, fmt, src);
    if (need < 0) cct_rt_fail("MOLDE str fmt sizing failed");
    char *tmp = (char*)malloc((size_t)need + 1);
    if (!tmp) cct_rt_fail("MOLDE str fmt allocation failed");
    int wrote = snprintf(tmp, (size_t)need + 1, fmt, src);
    if (wrote != need) cct_rt_fail("MOLDE str fmt write failed");
    cct_rt_molde_append(m, tmp, (size_t)wrote);
    free(tmp);
}

static char *cct_rt_molde_end(cct_rt_molde_ctx_t *m) {
    if (!m) return NULL;
    char *out_s = m->buf;
    m->buf = NULL;
    free(m);
    return out_s;
}

static long long cct_rt_verbum_len(const char *s) {
    return (long long)strlen(s ? s : "");
}

static char *cct_rt_verbum_concat(const char *a, const char *b) {
    const char *sa = a ? a : "";
    const char *sb = b ? b : "";
    size_t la = strlen(sa);
    size_t lb = strlen(sb);
    char *out_s = (char*)malloc(la + lb + 1);
    if (!out_s) cct_rt_fail("verbum concat allocation failed");
    memcpy(out_s, sa, la);
    memcpy(out_s + la, sb, lb);
    out_s[la + lb] = '\0';
    return out_s;
}

static long long cct_rt_verbum_compare(const char *a, const char *b) {
    int cmp = strcmp(a ? a : "", b ? b : "");
    if (cmp < 0) return -1LL;
    if (cmp > 0) return 1LL;
    return 0LL;
}

static char *cct_rt_verbum_substring(const char *s, long long inicio, long long fim) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    if (inicio < 0 || fim < 0 || inicio > fim || (size_t)fim > slen) {
        cct_rt_fail("verbum substring bounds invalid");
    }
    size_t start = (size_t)inicio;
    size_t end = (size_t)fim;
    size_t out_len = end - start;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum substring allocation failed");
    if (out_len > 0) memcpy(out_s, src + start, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    size_t begin = 0;
    while (begin < slen && isspace((unsigned char)src[begin])) begin++;
    size_t end = slen;
    while (end > begin && isspace((unsigned char)src[end - 1])) end--;
    size_t out_len = end - begin;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum trim allocation failed");
    if (out_len > 0) memcpy(out_s, src + begin, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static long long cct_rt_verbum_find(const char *s, const char *sub) {
    const char *hay = s ? s : "";
    const char *needle = sub ? sub : "";
    if (*needle == '\0') return 0LL;
    const char *p = strstr(hay, needle);
    if (!p) return -1LL;
    return (long long)(p - hay);
}

static long long cct_rt_verbum_char_at(const char *s, long long i) {
    const char *src = s ? s : "";
    size_t n = strlen(src);
    if (i < 0 || (size_t)i >= n) cct_rt_fail("verbum char_at index out of bounds");
    return (long long)(unsigned char)src[(size_t)i];
}

static char *cct_rt_verbum_from_char(long long c) {
    if (c < 0 || c > 255) cct_rt_fail("verbum from_char expects byte range 0..255");
    char *out_s = (char*)malloc(2);
    if (!out_s) cct_rt_fail("verbum from_char allocation failed");
    out_s[0] = (char)(unsigned char)c;
    out_s[1] = '\0';
    return out_s;
}

static long long cct_rt_verbum_starts_with(const char *s, const char *prefix) {
    const char *src = s ? s : "";
    const char *pre = prefix ? prefix : "";
    size_t slen = strlen(src);
    size_t plen = strlen(pre);
    if (plen > slen) return 0LL;
    return (strncmp(src, pre, plen) == 0) ? 1LL : 0LL;
}

static long long cct_rt_verbum_ends_with(const char *s, const char *suffix) {
    const char *src = s ? s : "";
    const char *suf = suffix ? suffix : "";
    size_t slen = strlen(src);
    size_t suflen = strlen(suf);
    if (suflen > slen) return 0LL;
    return (memcmp(src + (slen - suflen), suf, suflen) == 0) ? 1LL : 0LL;
}

static char *cct_rt_verbum_strip_prefix(const char *s, const char *prefix) {
    const char *src = s ? s : "";
    const char *pre = prefix ? prefix : "";
    size_t slen = strlen(src);
    size_t plen = strlen(pre);
    if (!cct_rt_verbum_starts_with(src, pre)) return (char*)src;
    return cct_rt_verbum_substring(src, (long long)plen, (long long)slen);
}

static char *cct_rt_verbum_strip_suffix(const char *s, const char *suffix) {
    const char *src = s ? s : "";
    const char *suf = suffix ? suffix : "";
    size_t slen = strlen(src);
    size_t suflen = strlen(suf);
    if (!cct_rt_verbum_ends_with(src, suf)) return (char*)src;
    return cct_rt_verbum_substring(src, 0LL, (long long)(slen - suflen));
}

static char *cct_rt_verbum_replace(const char *s, const char *from, const char *to) {
    const char *src = s ? s : "";
    const char *needle = from ? from : "";
    const char *repl = to ? to : "";
    size_t from_len = strlen(needle);
    if (from_len == 0) return (char*)src;
    const char *found = strstr(src, needle);
    if (!found) return (char*)src;
    size_t pre = (size_t)(found - src);
    size_t to_len = strlen(repl);
    size_t src_len = strlen(src);
    size_t out_len = src_len - from_len + to_len;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum replace allocation failed");
    if (pre > 0) memcpy(out_s, src, pre);
    if (to_len > 0) memcpy(out_s + pre, repl, to_len);
    strcpy(out_s + pre + to_len, found + from_len);
    return out_s;
}

static char *cct_rt_verbum_replace_all(const char *s, const char *from, const char *to) {
    const char *src = s ? s : "";
    const char *needle = from ? from : "";
    const char *repl = to ? to : "";
    size_t from_len = strlen(needle);
    if (from_len == 0) return (char*)src;
    size_t to_len = strlen(repl);
    size_t src_len = strlen(src);
    size_t count = 0;
    const char *p = src;
    while ((p = strstr(p, needle)) != NULL) {
        count++;
        p += from_len;
    }
    if (count == 0) return (char*)src;
    size_t out_len = src_len;
    if (to_len >= from_len) {
        out_len += count * (to_len - from_len);
    } else {
        out_len -= count * (from_len - to_len);
    }
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum replace_all allocation failed");
    const char *cur = src;
    char *w = out_s;
    while ((p = strstr(cur, needle)) != NULL) {
        size_t seg_len = (size_t)(p - cur);
        if (seg_len > 0) memcpy(w, cur, seg_len);
        w += seg_len;
        if (to_len > 0) memcpy(w, repl, to_len);
        w += to_len;
        cur = p + from_len;
    }
    strcpy(w, cur);
    return out_s;
}

static char *cct_rt_verbum_to_upper(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    char *out_s = (char*)malloc(slen + 1);
    if (!out_s) cct_rt_fail("verbum to_upper allocation failed");
    for (size_t i = 0; i < slen; i++) {
        unsigned char ch = (unsigned char)src[i];
        if (ch >= 'a' && ch <= 'z') ch = (unsigned char)(ch - ('a' - 'A'));
        out_s[i] = (char)ch;
    }
    out_s[slen] = '\0';
    return out_s;
}

static char *cct_rt_verbum_to_lower(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    char *out_s = (char*)malloc(slen + 1);
    if (!out_s) cct_rt_fail("verbum to_lower allocation failed");
    for (size_t i = 0; i < slen; i++) {
        unsigned char ch = (unsigned char)src[i];
        if (ch >= 'A' && ch <= 'Z') ch = (unsigned char)(ch + ('a' - 'A'));
        out_s[i] = (char)ch;
    }
    out_s[slen] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim_left(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    size_t begin = 0;
    while (begin < slen && isspace((unsigned char)src[begin])) begin++;
    size_t out_len = slen - begin;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum trim_left allocation failed");
    if (out_len > 0) memcpy(out_s, src + begin, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim_right(const char *s) {
    const char *src = s ? s : "";
    size_t end = strlen(src);
    while (end > 0 && isspace((unsigned char)src[end - 1])) end--;
    char *out_s = (char*)malloc(end + 1);
    if (!out_s) cct_rt_fail("verbum trim_right allocation failed");
    if (end > 0) memcpy(out_s, src, end);
    out_s[end] = '\0';
    return out_s;
}

static char *cct_rt_verbum_trim_char(const char *s, long long c) {
    const char *src = s ? s : "";
    if (c < 0 || c > 255) cct_rt_fail("verbum trim_char expects byte range 0..255");
    unsigned char ch = (unsigned char)c;
    size_t slen = strlen(src);
    size_t begin = 0;
    size_t end = slen;
    while (begin < slen && (unsigned char)src[begin] == ch) begin++;
    while (end > begin && (unsigned char)src[end - 1] == ch) end--;
    size_t out_len = end - begin;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum trim_char allocation failed");
    if (out_len > 0) memcpy(out_s, src + begin, out_len);
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_repeat(const char *s, long long n) {
    const char *src = s ? s : "";
    if (n < 0) cct_rt_fail("verbum repeat count negativo");
    if (n == 0) return (char*)"";
    size_t slen = strlen(src);
    if (slen == 0) return (char*)"";
    size_t count = (size_t)n;
    if (slen > (SIZE_MAX - 1) / count) cct_rt_fail("verbum repeat allocation overflow");
    size_t out_len = slen * count;
    char *out_s = (char*)malloc(out_len + 1);
    if (!out_s) cct_rt_fail("verbum repeat allocation failed");
    char *w = out_s;
    for (size_t i = 0; i < count; i++) {
        memcpy(w, src, slen);
        w += slen;
    }
    out_s[out_len] = '\0';
    return out_s;
}

static char *cct_rt_verbum_pad_left(const char *s, long long width, long long fill) {
    const char *src = s ? s : "";
    if (fill < 0 || fill > 255) cct_rt_fail("verbum pad fill expects byte range 0..255");
    if (width < 0) return (char*)src;
    size_t slen = strlen(src);
    size_t w = (size_t)width;
    if (slen >= w) return (char*)src;
    size_t pad = w - slen;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("verbum pad_left allocation failed");
    memset(out_s, (int)(unsigned char)fill, pad);
    memcpy(out_s + pad, src, slen);
    out_s[w] = '\0';
    return out_s;
}

static char *cct_rt_verbum_pad_right(const char *s, long long width, long long fill) {
    const char *src = s ? s : "";
    if (fill < 0 || fill > 255) cct_rt_fail("verbum pad fill expects byte range 0..255");
    if (width < 0) return (char*)src;
    size_t slen = strlen(src);
    size_t w = (size_t)width;
    if (slen >= w) return (char*)src;
    size_t pad = w - slen;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("verbum pad_right allocation failed");
    memcpy(out_s, src, slen);
    memset(out_s + slen, (int)(unsigned char)fill, pad);
    out_s[w] = '\0';
    return out_s;
}

static char *cct_rt_verbum_center(const char *s, long long width, long long fill) {
    const char *src = s ? s : "";
    if (fill < 0 || fill > 255) cct_rt_fail("verbum pad fill expects byte range 0..255");
    if (width < 0) return (char*)src;
    size_t slen = strlen(src);
    size_t w = (size_t)width;
    if (slen >= w) return (char*)src;
    size_t total = w - slen;
    size_t left = total / 2;
    size_t right = total - left;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("verbum center allocation failed");
    memset(out_s, (int)(unsigned char)fill, left);
    memcpy(out_s + left, src, slen);
    memset(out_s + left + slen, (int)(unsigned char)fill, right);
    out_s[w] = '\0';
    return out_s;
}

static long long cct_rt_verbum_last_find(const char *s, const char *sub) {
    const char *src = s ? s : "";
    const char *needle = sub ? sub : "";
    size_t slen = strlen(src);
    size_t nlen = strlen(needle);
    if (nlen == 0) return (long long)slen;
    const char *last = NULL;
    const char *p = src;
    while ((p = strstr(p, needle)) != NULL) {
        last = p;
        p += 1;
    }
    if (!last) return -1LL;
    return (long long)(last - src);
}

static long long cct_rt_verbum_find_from(const char *s, const char *sub, long long offset) {
    const char *src = s ? s : "";
    const char *needle = sub ? sub : "";
    size_t slen = strlen(src);
    if (offset < 0 || (size_t)offset > slen) cct_rt_fail("verbum find_from offset invalido");
    size_t nlen = strlen(needle);
    if (nlen == 0) return offset;
    size_t i = (size_t)offset;
    while (i + nlen <= slen) {
        if (memcmp(src + i, needle, nlen) == 0) return (long long)i;
        i++;
    }
    return -1LL;
}

static long long cct_rt_verbum_count_occurrences(const char *s, const char *sub) {
    const char *src = s ? s : "";
    const char *needle = sub ? sub : "";
    size_t nlen = strlen(needle);
    if (nlen == 0) return 0LL;
    long long count = 0;
    const char *p = src;
    while ((p = strstr(p, needle)) != NULL) {
        count++;
        p += nlen;
    }
    return count;
}

static char *cct_rt_verbum_reverse(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    char *out_s = (char*)malloc(slen + 1);
    if (!out_s) cct_rt_fail("verbum reverse allocation failed");
    for (size_t i = 0; i < slen; i++) {
        out_s[i] = src[slen - 1 - i];
    }
    out_s[slen] = '\0';
    return out_s;
}

static long long cct_rt_verbum_equals_ignore_case(const char *a, const char *b) {
    const char *sa = a ? a : "";
    const char *sb = b ? b : "";
    size_t la = strlen(sa);
    size_t lb = strlen(sb);
    if (la != lb) return 0LL;
    for (size_t i = 0; i < la; i++) {
        unsigned char ca = (unsigned char)sa[i];
        unsigned char cb = (unsigned char)sb[i];
        if (ca >= 'A' && ca <= 'Z') ca = (unsigned char)(ca + ('a' - 'A'));
        if (cb >= 'A' && cb <= 'Z') cb = (unsigned char)(cb + ('a' - 'A'));
        if (ca != cb) return 0LL;
    }
    return 1LL;
}

static char *cct_rt_verbum_slice(const char *s, long long inicio, long long comprimento) {
    const char *src = s ? s : "";
    long long slen = (long long)strlen(src);
    if (inicio < 0 || comprimento < 0 || inicio > slen || comprimento > (slen - inicio)) {
        cct_rt_fail("verbum slice bounds invalid");
    }
    return cct_rt_verbum_substring(src, inicio, inicio + comprimento);
}

static long long cct_rt_verbum_is_ascii(const char *s) {
    const char *src = s ? s : "";
    for (const unsigned char *p = (const unsigned char*)src; *p; ++p) {
        if (*p > 127U) return 0LL;
    }
    return 1LL;
}

static void *cct_rt_verbum_split(const char *s, const char *sep) {
    const char *src = s ? s : "";
    const char *delim = sep ? sep : "";
    size_t slen = strlen(src);
    size_t dlen = strlen(delim);
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    if (slen == 0) {
        char *empty = (char*)"";
        cct_rt_fluxus_push((void*)out_f, (const void*)&empty);
        return (void*)out_f;
    }
    if (dlen == 0) {
        for (size_t i = 0; i < slen; i++) {
            char *piece = cct_rt_verbum_substring(src, (long long)i, (long long)(i + 1));
            cct_rt_fluxus_push((void*)out_f, (const void*)&piece);
        }
        return (void*)out_f;
    }
    const char *cur = src;
    const char *p = strstr(cur, delim);
    while (p) {
        char *piece = cct_rt_verbum_substring(src, (long long)(cur - src), (long long)(p - src));
        cct_rt_fluxus_push((void*)out_f, (const void*)&piece);
        cur = p + dlen;
        p = strstr(cur, delim);
    }
    char *tail = cct_rt_verbum_substring(src, (long long)(cur - src), (long long)slen);
    cct_rt_fluxus_push((void*)out_f, (const void*)&tail);
    return (void*)out_f;
}

static void *cct_rt_verbum_split_char(const char *s, long long c) {
    if (c < 0 || c > 255) cct_rt_fail("verbum split_char expects byte range 0..255");
    char sep_buf[2];
    sep_buf[0] = (char)(unsigned char)c;
    sep_buf[1] = '\0';
    return cct_rt_verbum_split(s, sep_buf);
}

static char *cct_rt_verbum_join(void *parts_ptr, const char *sep) {
    if (!parts_ptr) cct_rt_fail("verbum join received null parts");
    cct_rt_fluxus_t *parts = (cct_rt_fluxus_t*)parts_ptr;
    if (parts->elem_size != (long long)sizeof(char*)) cct_rt_fail("verbum join requer fluxus de VERBUM");
    if (parts->len <= 0) return (char*)"";
    const char *delim = sep ? sep : "";
    size_t dlen = strlen(delim);
    char **items = (char**)parts->data;
    size_t total = 0;
    for (long long i = 0; i < parts->len; i++) {
        const char *piece = items[i] ? items[i] : "";
        size_t plen = strlen(piece);
        if (SIZE_MAX - total < plen) cct_rt_fail("verbum join allocation overflow");
        total += plen;
        if (i + 1 < parts->len) {
            if (SIZE_MAX - total < dlen) cct_rt_fail("verbum join allocation overflow");
            total += dlen;
        }
    }
    char *out_s = (char*)malloc(total + 1);
    if (!out_s) cct_rt_fail("verbum join allocation failed");
    char *w = out_s;
    for (long long i = 0; i < parts->len; i++) {
        const char *piece = items[i] ? items[i] : "";
        size_t plen = strlen(piece);
        if (plen > 0) {
            memcpy(w, piece, plen);
            w += plen;
        }
        if (i + 1 < parts->len && dlen > 0) {
            memcpy(w, delim, dlen);
            w += dlen;
        }
    }
    *w = '\0';
    return out_s;
}

static void *cct_rt_verbum_lines(const char *s) {
    cct_rt_fluxus_t *out_f = (cct_rt_fluxus_t*)cct_rt_verbum_split_char(s, 10LL);
    if (out_f->elem_size != (long long)sizeof(char*)) cct_rt_fail("verbum lines requer fluxus de VERBUM");
    char **items = (char**)out_f->data;
    for (long long i = 0; i < out_f->len; i++) {
        const char *piece = items[i] ? items[i] : "";
        size_t plen = strlen(piece);
        if (plen > 0 && (unsigned char)piece[plen - 1] == 13U) {
            items[i] = cct_rt_verbum_substring(piece, 0LL, (long long)(plen - 1));
        }
    }
    return (void*)out_f;
}

static void *cct_rt_verbum_words(const char *s) {
    const char *src = s ? s : "";
    size_t slen = strlen(src);
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    size_t i = 0;
    while (i < slen) {
        while (i < slen) {
            unsigned char ch = (unsigned char)src[i];
            if (!(ch == 32U || ch == 9U || ch == 10U || ch == 13U)) break;
            i++;
        }
        if (i >= slen) break;
        size_t start = i;
        while (i < slen) {
            unsigned char ch = (unsigned char)src[i];
            if (ch == 32U || ch == 9U || ch == 10U || ch == 13U) break;
            i++;
        }
        char *piece = cct_rt_verbum_substring(src, (long long)start, (long long)i);
        cct_rt_fluxus_push((void*)out_f, (const void*)&piece);
    }
    return (void*)out_f;
}

static long long cct_rt_char_is_digit(long long c) {
    return (c >= 48LL && c <= 57LL) ? 1LL : 0LL;
}

static long long cct_rt_char_is_alpha(long long c) {
    if (c >= 65LL && c <= 90LL) return 1LL;
    if (c >= 97LL && c <= 122LL) return 1LL;
    return 0LL;
}

static long long cct_rt_char_is_whitespace(long long c) {
    return (c == 32LL || c == 9LL || c == 10LL || c == 13LL) ? 1LL : 0LL;
}

static char *cct_rt_env_get(const char *name) {
    const char *k = name ? name : "";
    const char *v = getenv(k);
    return (char*)(v ? v : "");
}

static long long cct_rt_env_has(const char *name) {
    const char *k = name ? name : "";
    return getenv(k) ? 1LL : 0LL;
}

static char *cct_rt_env_cwd(void) {
    char buf[4096];
    if (!cct_rt_getcwd(buf, sizeof(buf))) cct_rt_fail("env cwd failed");
    size_t n = strlen(buf);
    char *out_s = (char*)malloc(n + 1);
    if (!out_s) cct_rt_fail("env cwd allocation failed");
    memcpy(out_s, buf, n + 1);
    return out_s;
}

typedef struct {
    const char *src;
    long long len;
    long long pos;
} cct_rt_scan_t;

static void *cct_rt_scan_init(const char *s) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)malloc(sizeof(cct_rt_scan_t));
    if (!c) cct_rt_fail("scan init allocation failed");
    c->src = s ? s : "";
    c->len = (long long)strlen(c->src);
    c->pos = 0;
    return c;
}

static long long cct_rt_scan_pos(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan pos null cursor");
    return c->pos;
}

static long long cct_rt_scan_eof(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan eof null cursor");
    return (c->pos >= c->len) ? 1LL : 0LL;
}

static long long cct_rt_scan_peek(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan peek null cursor");
    if (c->pos >= c->len) cct_rt_fail("scan peek at eof");
    return (long long)(unsigned char)c->src[c->pos];
}

static long long cct_rt_scan_next(void *p) {
    cct_rt_scan_t *c = (cct_rt_scan_t*)p;
    if (!c) cct_rt_fail("scan next null cursor");
    if (c->pos >= c->len) cct_rt_fail("scan next at eof");
    long long out_ch = (long long)(unsigned char)c->src[c->pos];
    c->pos += 1;
    return out_ch;
}

static void cct_rt_scan_free(void *p) {
    if (!p) return;
    free(p);
}

typedef struct {
    char *data;
    long long len;
    long long cap;
} cct_rt_builder_t;

static cct_rt_builder_t *cct_rt_builder_require_nonnull(void *p, const char *ctx) {
    cct_rt_builder_t *b = (cct_rt_builder_t*)p;
    if (!b) cct_rt_fail(ctx ? ctx : "builder null pointer");
    return b;
}

static void cct_rt_builder_reserve(cct_rt_builder_t *b, long long extra) {
    if (!b) cct_rt_fail("builder reserve null pointer");
    if (extra < 0) cct_rt_fail("builder reserve negative extra");
    if (b->cap <= 0) cct_rt_fail("builder reserve invalid capacity");
    long long need = b->len + extra + 1;
    if (need <= b->cap) return;
    long long new_cap = b->cap;
    while (new_cap < need) {
        if (new_cap > (9223372036854775807LL / 2)) {
            new_cap = need;
            break;
        }
        new_cap *= 2;
    }
    char *new_data = (char*)realloc(b->data, (size_t)new_cap);
    if (!new_data) cct_rt_fail("builder reserve allocation failed");
    b->data = new_data;
    b->cap = new_cap;
}

static void *cct_rt_builder_init(void) {
    cct_rt_builder_t *b = (cct_rt_builder_t*)malloc(sizeof(cct_rt_builder_t));
    if (!b) cct_rt_fail("builder init allocation failed");
    b->cap = 32;
    b->len = 0;
    b->data = (char*)malloc((size_t)b->cap);
    if (!b->data) cct_rt_fail("builder init buffer allocation failed");
    b->data[0] = '\0';
    return b;
}

static void cct_rt_builder_append(void *p, const char *s) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder append null pointer");
    const char *src = s ? s : "";
    long long slen = (long long)strlen(src);
    cct_rt_builder_reserve(b, slen);
    memcpy(b->data + b->len, src, (size_t)slen + 1);
    b->len += slen;
}

static void cct_rt_builder_append_char(void *p, long long c) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder append_char null pointer");
    if (c < 0 || c > 255) cct_rt_fail("builder append_char expects byte range 0..255");
    cct_rt_builder_reserve(b, 1);
    b->data[b->len] = (char)(unsigned char)c;
    b->len += 1;
    b->data[b->len] = '\0';
}

static long long cct_rt_builder_len(void *p) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder len null pointer");
    return b->len;
}

static char *cct_rt_builder_to_verbum(void *p) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder to_verbum null pointer");
    char *out_s = (char*)malloc((size_t)b->len + 1);
    if (!out_s) cct_rt_fail("builder to_verbum allocation failed");
    memcpy(out_s, b->data, (size_t)b->len + 1);
    return out_s;
}

static void cct_rt_builder_clear(void *p) {
    cct_rt_builder_t *b = cct_rt_builder_require_nonnull(p, "builder clear null pointer");
    b->len = 0;
    b->data[0] = '\0';
}

static void cct_rt_builder_free(void *p) {
    cct_rt_builder_t *b = (cct_rt_builder_t*)p;
    if (!b) return;
    free(b->data);
    free(b);
}

typedef struct {
    cct_rt_builder_t *buf;
    long long indent;
    int at_line_start;
} cct_rt_writer_t;

static cct_rt_writer_t *cct_rt_writer_require_nonnull(void *p, const char *ctx) {
    cct_rt_writer_t *w = (cct_rt_writer_t*)p;
    if (!w) cct_rt_fail(ctx ? ctx : "writer null pointer");
    return w;
}

static void cct_rt_writer_apply_indent(cct_rt_writer_t *w) {
    if (!w || !w->at_line_start) return;
    long long spaces = w->indent * 2;
    for (long long i = 0; i < spaces; i++) {
        cct_rt_builder_append_char((void*)w->buf, 32LL);
    }
    w->at_line_start = 0;
}

static void *cct_rt_writer_init(void) {
    cct_rt_writer_t *w = (cct_rt_writer_t*)malloc(sizeof(cct_rt_writer_t));
    if (!w) cct_rt_fail("writer init allocation failed");
    w->buf = (cct_rt_builder_t*)cct_rt_builder_init();
    w->indent = 0;
    w->at_line_start = 1;
    return w;
}

static void cct_rt_writer_indent(void *p) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer indent null pointer");
    w->indent += 1;
}

static void cct_rt_writer_dedent(void *p) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer dedent null pointer");
    if (w->indent <= 0) cct_rt_fail("writer dedent underflow");
    w->indent -= 1;
}

static void cct_rt_writer_write(void *p, const char *s) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer write null pointer");
    const char *src = s ? s : "";
    size_t n = strlen(src);
    if (n == 0) return;
    cct_rt_writer_apply_indent(w);
    cct_rt_builder_append((void*)w->buf, src);
    w->at_line_start = (src[n - 1] == '\n') ? 1 : 0;
}

static void cct_rt_writer_writeln(void *p, const char *s) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer writeln null pointer");
    const char *src = s ? s : "";
    cct_rt_writer_apply_indent(w);
    cct_rt_builder_append((void*)w->buf, src);
    cct_rt_builder_append_char((void*)w->buf, 10LL);
    w->at_line_start = 1;
}

static char *cct_rt_writer_to_verbum(void *p) {
    cct_rt_writer_t *w = cct_rt_writer_require_nonnull(p, "writer to_verbum null pointer");
    return cct_rt_builder_to_verbum((void*)w->buf);
}

static void cct_rt_writer_free(void *p) {
    cct_rt_writer_t *w = (cct_rt_writer_t*)p;
    if (!w) return;
    cct_rt_builder_free((void*)w->buf);
    free(w);
}

