static char *cct_rt_fmt_stringify_int_padded(long long x, long long width, long long fill) {
    if (fill < 0 || fill > 255) cct_rt_fail("fmt stringify_int_padded fill fora do intervalo 0..255");
    char *base = cct_rt_fmt_stringify_int(x);
    if (width <= 0) return base;
    size_t len = strlen(base);
    size_t w = (size_t)width;
    if (len >= w) return base;
    size_t pad = w - len;
    char *out_s = (char*)malloc(w + 1);
    if (!out_s) cct_rt_fail("fmt stringify_int_padded allocation failed");
    memset(out_s, (int)(unsigned char)fill, pad);
    memcpy(out_s + pad, base, len + 1);
    return out_s;
}

