static char *cct_rt_fmt_format_1(const char *tmpl, const char *a) {
    const char *src = tmpl ? tmpl : "";
    const char *arg = a ? a : "";
    const char *pos = strstr(src, "{}");
    if (!pos) return (char*)src;
    size_t pre = (size_t)(pos - src);
    size_t alen = strlen(arg);
    size_t rest = strlen(pos + 2);
    char *out_s = (char*)malloc(pre + alen + rest + 1);
    if (!out_s) cct_rt_fail("fmt format_1 allocation failed");
    if (pre > 0) memcpy(out_s, src, pre);
    if (alen > 0) memcpy(out_s + pre, arg, alen);
    memcpy(out_s + pre + alen, pos + 2, rest + 1);
    return out_s;
}

static char *cct_rt_fmt_format_2(const char *tmpl, const char *a, const char *b) {
    char *step1 = cct_rt_fmt_format_1(tmpl, a);
    return cct_rt_fmt_format_1(step1, b);
}

static char *cct_rt_fmt_format_3(const char *tmpl, const char *a, const char *b, const char *c) {
    char *step = cct_rt_fmt_format_2(tmpl, a, b);
    return cct_rt_fmt_format_1(step, c);
}

static char *cct_rt_fmt_format_4(const char *tmpl, const char *a, const char *b, const char *c, const char *d) {
    char *step = cct_rt_fmt_format_3(tmpl, a, b, c);
    return cct_rt_fmt_format_1(step, d);
}

static char *cct_rt_fmt_repeat_char(long long c, long long n) {
    if (c < 0 || c > 255) cct_rt_fail("fmt repeat_char expects byte range 0..255");
    if (n <= 0) return (char*)"";
    size_t count = (size_t)n;
    char *out_s = (char*)malloc(count + 1);
    if (!out_s) cct_rt_fail("fmt repeat_char allocation failed");
    memset(out_s, (int)(unsigned char)c, count);
    out_s[count] = '\0';
    return out_s;
}

static char *cct_rt_fmt_table_row(void *parts_ptr, const long long *widths, long long ncols) {
    if (!parts_ptr) cct_rt_fail("fmt table_row received null parts");
    if (!widths) cct_rt_fail("fmt table_row received null widths");
    if (ncols < 0) cct_rt_fail("fmt table_row ncols invalido");
    cct_rt_fluxus_t *parts = (cct_rt_fluxus_t*)parts_ptr;
    if (parts->elem_size != (long long)sizeof(char*)) cct_rt_fail("fmt table_row requer fluxus de VERBUM");
    char **items = (char**)parts->data;
    cct_rt_builder_t *b = (cct_rt_builder_t*)cct_rt_builder_init();
    for (long long i = 0; i < ncols; i++) {
        const char *piece = "";
        if (i < parts->len && items) piece = items[i] ? items[i] : "";
        long long w = widths[i];
        if (w < 0) w = 0;
        size_t plen = strlen(piece);
        size_t copy_n = plen;
        if ((long long)copy_n > w) copy_n = (size_t)w;
        if (copy_n > 0) {
            char *slice = cct_rt_verbum_substring(piece, 0LL, (long long)copy_n);
            cct_rt_builder_append((void*)b, slice);
        }
        for (long long pad = (long long)copy_n; pad < w; pad++) {
            cct_rt_builder_append_char((void*)b, 32LL);
        }
        if (i + 1 < ncols) cct_rt_builder_append((void*)b, " | ");
    }
    char *out_s = cct_rt_builder_to_verbum((void*)b);
    cct_rt_builder_free((void*)b);
    return out_s;
}

static long long cct_rt_fmt_parse_int_or_fail(const char *s) {
    const char *src = s ? s : "";
    while (*src && isspace((unsigned char)*src)) src++;
    if (!*src) cct_rt_fail("fmt parse_int invalid input");
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, 10);
    if (errno != 0 || end == src) cct_rt_fail("fmt parse_int invalid input");
    while (*end && isspace((unsigned char)*end)) end++;
    if (*end) cct_rt_fail("fmt parse_int invalid input");
    return v;
}

static double cct_rt_fmt_parse_real_or_fail(const char *s) {
    const char *src = s ? s : "";
    while (*src && isspace((unsigned char)*src)) src++;
    if (!*src) cct_rt_fail("fmt parse_real invalid input");
    errno = 0;
    char *end = NULL;
    double v = strtod(src, &end);
    if (errno != 0 || end == src) cct_rt_fail("fmt parse_real invalid input");
    while (*end && isspace((unsigned char)*end)) end++;
    if (*end) cct_rt_fail("fmt parse_real invalid input");
    return v;
}

static int cct_rt_parse_has_edge_ws(const char *s) {
    const char *src = s ? s : "";
    size_t n = strlen(src);
    if (n == 0) return 1;
    if (isspace((unsigned char)src[0])) return 1;
    if (isspace((unsigned char)src[n - 1])) return 1;
    return 0;
}

static void *cct_rt_parse_try_int(const char *s) {
    const char *src = s ? s : "";
    if (cct_rt_parse_has_edge_ws(src)) return cct_rt_option_none(sizeof(long long));
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, 10);
    if (errno != 0 || end == src || *end != '\0') return cct_rt_option_none(sizeof(long long));
    return cct_rt_option_some((const void*)&v, sizeof(long long));
}

static void *cct_rt_parse_try_real(const char *s) {
    const char *src = s ? s : "";
    if (cct_rt_parse_has_edge_ws(src)) return cct_rt_option_none(sizeof(double));
    errno = 0;
    char *end = NULL;
    double v = strtod(src, &end);
    if (errno != 0 || end == src || *end != '\0') return cct_rt_option_none(sizeof(double));
    return cct_rt_option_some((const void*)&v, sizeof(double));
}

static void *cct_rt_parse_try_bool(const char *s) {
    const char *src = s ? s : "";
    if (strcmp(src, "true") == 0) {
        long long v = 1LL;
        return cct_rt_option_some((const void*)&v, sizeof(long long));
    }
    if (strcmp(src, "false") == 0) {
        long long v = 0LL;
        return cct_rt_option_some((const void*)&v, sizeof(long long));
    }
    return cct_rt_option_none(sizeof(long long));
}

static long long cct_rt_parse_int_hex_raw(const char *s, int *ok) {
    const char *src = s ? s : "";
    if (ok) *ok = 0;
    if (cct_rt_parse_has_edge_ws(src)) return 0LL;
    size_t n = strlen(src);
    size_t pos = 0;
    if (src[pos] == '+' || src[pos] == '-') pos += 1;
    if (pos >= n) return 0LL;
    if (src[pos] == '0' && (pos + 1) < n && (src[pos + 1] == 'x' || src[pos + 1] == 'X')) pos += 2;
    if (pos >= n) return 0LL;
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, 16);
    if (errno != 0 || end == src || *end != '\0') return 0LL;
    if (ok) *ok = 1;
    return v;
}

static void *cct_rt_parse_try_int_hex(const char *s) {
    int ok = 0;
    long long v = cct_rt_parse_int_hex_raw(s, &ok);
    if (!ok) return cct_rt_option_none(sizeof(long long));
    return cct_rt_option_some((const void*)&v, sizeof(long long));
}

static long long cct_rt_parse_int_hex(const char *s) {
    int ok = 0;
    long long v = cct_rt_parse_int_hex_raw(s, &ok);
    if (!ok) cct_rt_fail("parse parse_int_hex valor invalido");
    return v;
}

static void *cct_rt_parse_try_int_radix(const char *s, long long radix) {
    if (radix < 2LL || radix > 36LL) return cct_rt_option_none(sizeof(long long));
    const char *src = s ? s : "";
    if (cct_rt_parse_has_edge_ws(src)) return cct_rt_option_none(sizeof(long long));
    errno = 0;
    char *end = NULL;
    long long v = strtoll(src, &end, (int)radix);
    if (errno != 0 || end == src || *end != '\0') return cct_rt_option_none(sizeof(long long));
    return cct_rt_option_some((const void*)&v, sizeof(long long));
}

static long long cct_rt_parse_int_radix(const char *s, long long radix) {
    if (radix < 2LL || radix > 36LL) cct_rt_fail("parse parse_int_radix radix invalida");
    void *opt = cct_rt_parse_try_int_radix(s, radix);
    if (!cct_rt_option_is_some(opt)) cct_rt_fail("parse parse_int_radix valor invalido");
    long long out_v = *(long long*)cct_rt_option_unwrap_ptr(opt);
    cct_rt_option_free(opt);
    return out_v;
}

static long long cct_rt_parse_is_int(const char *s) {
    void *opt = cct_rt_parse_try_int(s);
    long long ok = cct_rt_option_is_some(opt);
    cct_rt_option_free(opt);
    return ok;
}

static long long cct_rt_parse_is_real(const char *s) {
    void *opt = cct_rt_parse_try_real(s);
    long long ok = cct_rt_option_is_some(opt);
    cct_rt_option_free(opt);
    return ok;
}

static void *cct_rt_parse_csv_line(const char *s, long long sep) {
    if (sep < 0LL || sep > 255LL) cct_rt_fail("parse parse_csv_line separador fora do intervalo 0..255");
    const char *src = s ? s : "";
    size_t n = strlen(src);
    size_t i = 0;
    unsigned char usep = (unsigned char)sep;
    cct_rt_fluxus_t *out_f = cct_rt_fluxus_create((long long)sizeof(char*));
    for (;;) {
        if (i == n) {
            char *empty = (char*)"";
            cct_rt_fluxus_push((void*)out_f, (const void*)&empty);
            break;
        }
        if ((unsigned char)src[i] == 34U) {
            size_t j = i + 1;
            while (j < n && (unsigned char)src[j] != 34U) j++;
            if (j >= n) cct_rt_fail("parse parse_csv_line aspas sem fechamento");
            char *field = cct_rt_verbum_substring(src, (long long)(i + 1), (long long)j);
            cct_rt_fluxus_push((void*)out_f, (const void*)&field);
            i = j + 1;
            if (i >= n) break;
            if ((unsigned char)src[i] != usep) cct_rt_fail("parse parse_csv_line formato invalido");
            i += 1;
            continue;
        }
        size_t j = i;
        while (j < n && (unsigned char)src[j] != usep) j++;
        char *field = cct_rt_verbum_substring(src, (long long)i, (long long)j);
        cct_rt_fluxus_push((void*)out_f, (const void*)&field);
        if (j >= n) break;
        i = j + 1;
    }
    return (void*)out_f;
}

