static void cct_rt_sock_connect(void *sock_ptr, const char *host, long long port) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)host;
    (void)port;
    cct_rt_fail("sock_connect unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_connect recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_connect recebeu socket fechado");
    cct_rt_socket_validate_port(port);
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons((uint16_t)port);
    const char *node = (host && *host) ? host : "127.0.0.1";
    if (inet_pton(AF_INET, node, &addr.sin_addr) != 1) cct_rt_fail("sock_connect host invalido");
    if (connect(sock->fd, (const struct sockaddr*)&addr, (socklen_t)sizeof(addr)) == 0) {
        sock->domain = AF_INET;
        cct_rt_socket_clear_last_error();
        return;
    }
    if (!cct_rt_socket_is_local_host(host)) {
        cct_rt_socket_set_last_error("sock_connect falhou");
        cct_rt_fail("sock_connect falhou");
    }
    char unix_path[108];
    cct_rt_socket_make_unix_path(port, unix_path);
    int ufd = socket(AF_UNIX, sock->kind, 0);
    if (ufd < 0) {
        cct_rt_socket_set_last_error("sock_connect falhou");
        cct_rt_fail("sock_connect falhou");
    }
    struct sockaddr_un uaddr;
    memset(&uaddr, 0, sizeof(uaddr));
    uaddr.sun_family = AF_UNIX;
    strncpy(uaddr.sun_path, unix_path, sizeof(uaddr.sun_path) - 1);
    uaddr.sun_path[sizeof(uaddr.sun_path) - 1] = '\0';
    if (connect(ufd, (const struct sockaddr*)&uaddr, (socklen_t)sizeof(uaddr)) != 0) {
        close(ufd);
        cct_rt_socket_set_last_error("sock_connect falhou");
        cct_rt_fail("sock_connect falhou");
    }
    (void)close(sock->fd);
    sock->fd = ufd;
    sock->domain = AF_UNIX;
    sock->owns_unix_path = 0;
    sock->unix_path[0] = '\0';
    cct_rt_socket_clear_last_error();
#endif
}

static void cct_rt_sock_bind(void *sock_ptr, const char *host, long long port) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)host;
    (void)port;
    cct_rt_fail("sock_bind unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_bind recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_bind recebeu socket fechado");
    cct_rt_socket_validate_port(port);
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons((uint16_t)port);
    if (!host || !*host) addr.sin_addr.s_addr = htonl(INADDR_ANY);
    else if (inet_pton(AF_INET, host, &addr.sin_addr) != 1) cct_rt_fail("sock_bind host invalido");
    cct_rt_socket_enable_reuseaddr(sock->fd);
    if (bind(sock->fd, (const struct sockaddr*)&addr, (socklen_t)sizeof(addr)) == 0) {
        sock->domain = AF_INET;
        sock->owns_unix_path = 0;
        sock->unix_path[0] = '\0';
        cct_rt_socket_clear_last_error();
        return;
    }
    if (!cct_rt_socket_is_local_host(host)) {
        cct_rt_socket_set_last_error("sock_bind falhou");
        cct_rt_fractum_throw_str("sock_bind falhou");
        return;
    }
    char unix_path[108];
    cct_rt_socket_make_unix_path(port, unix_path);
    int ufd = socket(AF_UNIX, sock->kind, 0);
    if (ufd < 0) {
        cct_rt_socket_set_last_error("sock_bind falhou");
        cct_rt_fractum_throw_str("sock_bind falhou");
        return;
    }
    struct sockaddr_un uaddr;
    memset(&uaddr, 0, sizeof(uaddr));
    uaddr.sun_family = AF_UNIX;
    strncpy(uaddr.sun_path, unix_path, sizeof(uaddr.sun_path) - 1);
    uaddr.sun_path[sizeof(uaddr.sun_path) - 1] = '\0';
    unlink(unix_path);
    if (bind(ufd, (const struct sockaddr*)&uaddr, (socklen_t)sizeof(uaddr)) != 0) {
        close(ufd);
        cct_rt_socket_set_last_error("sock_bind falhou");
        cct_rt_fractum_throw_str("sock_bind falhou");
        return;
    }
    (void)close(sock->fd);
    sock->fd = ufd;
    sock->domain = AF_UNIX;
    sock->owns_unix_path = 1;
    strncpy(sock->unix_path, unix_path, sizeof(sock->unix_path) - 1);
    sock->unix_path[sizeof(sock->unix_path) - 1] = '\0';
    cct_rt_socket_clear_last_error();
#endif
}

